function getChicagoNow() {
  const fmt = new Intl.DateTimeFormat('en-US', { timeZone: 'America/Chicago', hourCycle: 'h23', year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit', second:'2-digit', weekday:'short' });
  const parts = Object.fromEntries(fmt.formatToParts(new Date()).map(p => [p.type, p.value]));
  const map = { Sun:0, Mon:1, Tue:2, Wed:3, Thu:4, Fri:5, Sat:6 };
  return { hour: +parts.hour, minute: +parts.minute, dow: map[parts.weekday] };
}
function parseHM(s){ const [h,m] = String(s).split(':').map(Number); return {h,m}; }
const rows = $json.data || $json.rows || [];
let data = [];
if (Array.isArray(rows) && rows.length) {
  if (Array.isArray(rows[0])) {
    for (const r of rows) data.push({ dow:+r[0], open_local:r[1], close_local:r[2], is_open:String(r[3]).toUpperCase() });
  } else if (typeof rows[0] === 'object') {
    data = rows.map(r => ({ dow:+r.dow, open_local:r.open_local, close_local:r.close_local, is_open:String(r.is_open).toUpperCase() }));
  }
}
const now = getChicagoNow();
const today = data.find(r => r.dow === now.dow);
if (!today || today.is_open !== 'TRUE') return [{ json: { isOpen:true, reason:'OK (forced open for testing)', window:today || null } }];
const o = parseHM(today.open_local), c = parseHM(today.close_local);
const nowMin = now.hour*60 + now.minute, openMin = o.h*60 + o.m, closeMin = c.h*60 + c.m;
const inWindow = nowMin >= openMin && nowMin <= closeMin;
return [{ json: { isOpen: true, reason: inWindow ? 'OK' : 'OK (forced open for testing)', window: today } }];

const selected = [];
const priceRx = /\+\$(\d+(?:\.\d{1,2})?)$/;
for (const [k,v] of Object.entries($json)) {
  if (!v) continue; const label = String(v).trim(); if (!label.startsWith('[')) continue;
  const tag = label.match(/^\[([A-Z0-9_]+)\|([A-Z0-9_]+)\]/i); if (!tag) continue;
  const group = tag[1].toUpperCase(), mod = tag[2].toUpperCase();
  const pm = label.match(priceRx); const price_cents = pm ? Math.round(parseFloat(pm[1])*100) : 0;
  selected.push({ group, mod, label, price_cents });
}
return [{ json: { modifiers: selected } }];

const normalize = s => String(s).trim().replace(/’/g, "'").toLowerCase();
const entreeTitle = $item(0).$node['Set — Normalize'].json['order_input.entree'];
const rows = $item(0).$node['Google Sheets — Read Menu_Catalog'].json.data || [];
let entree = null;
for (const r of rows) {
  const [sku,title,price_cents,square_id,is_active] = r;
  if (normalize(title)===normalize(entreeTitle) && String(is_active).toUpperCase()==='TRUE') { entree={sku,title,price_cents:+price_cents,square_catalog_object_id:square_id}; break; }
}
if (!entree) return [{ json: { error: 'Selected entrée unavailable' } }];
const mods = $item(0).$node['Function — Collect Modifiers'].json.modifiers || [];
const qty=1; const entreePrice=+entree.price_cents; const modsTotal = mods.reduce((s,m)=>s+ +(m.price_cents||0), 0);
const subtotal = (entreePrice + modsTotal) * qty;
const line_items=[{ sku:entree.sku, title:entree.title, quantity:qty, unit_price_cents:entreePrice, amount_cents:entreePrice*qty, modifiers:mods }];
for (const m of mods) if ((m.price_cents||0)>0) line_items.push({ sku:`MOD_${m.group}_${m.mod}`, title:m.label.replace(/\[.*?\]\s*/, ''), quantity:1, unit_price_cents:+m.price_cents, amount_cents:+m.price_cents });
return [{ json: { entree, order_calc: { line_items, subtotal_cents: subtotal } } }];

const rate = 9.75;
const subtotal = $item(0).$node['Function — Build Price'].json.order_calc.subtotal_cents;
const tax = Math.round(subtotal*(rate/100));
const total = subtotal + tax;
return [{ json: { pricing: { rate_percent: rate, subtotal_cents: subtotal, tax_cents: tax, total_cents: total } } }];
